 1→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
 2→import React, { FC, useCallback, useRef } from 'react';
 3→
 4→import { useFocusEffect } from '@react-navigation/native';
 5→import {
 6→  eventModalView,
 7→  eventScreenViewV3,
 8→  eventSelectContent,
 9→} from '~/constants/functions';
10→import { ScreenProps } from '../../routes/Models';
11→import PointsDetailView from './view';
12→
13→const PointsDetail: FC<ScreenProps<'PointsDetail'>> = ({
14→  navigation,
15→  route,
16→}) => {
17→  const hasFocused = useRef(false);
18→  const modalizeRef = useRef<PropsModalizeRef>(null);
19→
20→  useFocusEffect(
21→    useCallback(() => {
22→      if (!hasFocused.current) {
23→        eventScreenViewV3(
24→          'detalhe_extrato_hub_recompensas',
25→          'hub_recompensas_spmais',
26→          'monetizacao',
27→          {
28→            location_1: 'monetizacao',
29→            location_2: 'hub_recompensas_spmais',
30→            location_3: 'detalhe_extrato_hub_recompensas',
31→          },
32→        );
33→        hasFocused.current = true;
34→      }
35→      return () => {
36→        hasFocused.current = false;
37→      };
38→    }, []),
39→  );
40→
41→  const handleGoBack = () => {
42→    navigation.goBack();
43→  };
44→
45→  const handleOpenReportProblem = () => {
46→    eventSelectContent({
47→      content_type: 'cta',
48→      content_id: 'relatar_problema',
49→      location_1: 'monetizacao',
50→      location_2: 'hub_recompensas_spmais',
51→      location_3: 'detalhe_extrato_hub_recompensas',
52→    });
53→
54→    eventModalView({
55→      content_id: 'contato_telefones',
56→      location_1: 'monetizacao',
57→      location_2: 'hub_recompensas_spmais',
58→      location_3: 'detalhe_extrato_hub_recompensas',
59→    });
60→
61→    modalizeRef.current?.open?.();
62→  };
63→
64→  const handleCloseReportProblem = () => {
65→    modalizeRef.current?.close?.();
66→  };
67→
68→  const transaction = route.params?.transaction;
69→
70→  if (!transaction) {
71→    return null;
72→  }
73→
74→  return (
75→    <PointsDetailView
76→      handleGoBack={handleGoBack}
77→      transaction={transaction}
78→      modalizeRef={modalizeRef}
79→      handleOpenReportProblem={handleOpenReportProblem}
80→      handleCloseReportProblem={handleCloseReportProblem}
81→    />
82→  );
83→};
84→
85→export default PointsDetail;
