  3→type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
  4→type TagSubType =
  5→  | 'DRIVE_THRU'
  6→  | 'PEDAGIO'
  7→  | 'ESTACIONAMENTO'
  8→  | 'ABASTECIMENTO'
  9→  | 'LAVA_RAPIDO';
