 94→export const getVehicleInfo = (
 95→  transaction: PointsTransaction,
 96→): string | null => {
 97→  const fields: TransactionDetailField[] = transaction.details?.fields || [];
 98→
 99→  const marcaField = fields.find((f: TransactionDetailField) =>
100→    f.label?.toLowerCase().includes('marca'));
101→  const modeloField = fields.find((f: TransactionDetailField) =>
102→    f.label?.toLowerCase().includes('modelo'));
103→  const placaField = fields.find((f: TransactionDetailField) =>
104→    f.label?.toLowerCase().includes('placa'));
105→
106→  const marca = marcaField?.value || '';
107→  const modelo = modeloField?.value || '';
108→  const placa = placaField?.value || '';
109→
110→  if (marca && modelo && placa) {
111→    return `${marca} ${modelo} - ${placa}`;
112→  }
113→
114→  if (placa) {
115→    return placa;
116→  }
117→
118→  const origemField = fields.find(
119→    (f: TransactionDetailField) =>
120→      f.label?.toLowerCase().includes('origem') ||
121→      f.label?.toLowerCase().includes('origin'),
122→  );
123→
124→  if (origemField?.value) {
125→    return origemField.value;
126→  }
127→
128→  return null;
129→};
